import Foundation

func solve(piles: Array<Int64>) -> Int64 {
    // Sort the array
    var sortedPiles = piles
    sortedPiles.sort()

    let n = sortedPiles.count
    var result = 0

    // Since the length is divisible by 3, we can process the array in groups of 3
    for i in 0..<n/3 {
        // For each group of 3 elements, the median is the second element (index 1 in 0-based)
        let median = sortedPiles[i * 3 + 1]
        result += median
    }

    return Int64(result)
}
